import org.apache.kafka.clients.consumer.ConsumerConfig;
import org.apache.kafka.clients.consumer.ConsumerRecord;
import org.apache.kafka.clients.consumer.ConsumerRecords;
import org.apache.kafka.clients.consumer.KafkaConsumer;
import org.apache.kafka.common.errors.WakeupException;
import org.apache.kafka.common.serialization.StringDeserializer;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.time.Duration;
import java.util.Collections;
import java.util.Properties;
import java.util.concurrent.atomic.AtomicBoolean;

/**
 * Kafka consumer that consumes messages from the "inventory-updates" topic
 * and processes them idempotently.
 */
public class InventoryConsumer {
    private static final Logger LOG = LoggerFactory.getLogger(InventoryConsumer.class);
    private static final String TOPIC = "inventory-updates";
    private static final Duration POLL_TIMEOUT = Duration.ofMillis(100);

    private final KafkaConsumer<String, String> consumer;
    private final AtomicBoolean isShuttingDown = new AtomicBoolean(false);

    public InventoryConsumer(String bootstrapServers, String groupId) {
        Properties props = new Properties();
        props.put(ConsumerConfig.BOOTSTRAP_SERVERS_CONFIG, bootstrapServers);
        props.put(ConsumerConfig.GROUP_ID_CONFIG, groupId);
        props.put(ConsumerConfig.KEY_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.VALUE_DESERIALIZER_CLASS_CONFIG, StringDeserializer.class);
        props.put(ConsumerConfig.AUTO_OFFSET_RESET_CONFIG, "earliest");
        props.put(ConsumerConfig.ENABLE_AUTO_COMMIT_CONFIG, "false");

        this.consumer = new KafkaConsumer<>(props);
        setupShutdownHook();
    }

    private void setupShutdownHook() {
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            LOG.info("Shutdown signal received");
            isShuttingDown.set(true);
            consumer.wakeup();
        }));
    }

    public void run() {
        try {
            consumer.subscribe(Collections.singletonList(TOPIC));
            LOG.info("Subscribed to topic: {}", TOPIC);

            while (!isShuttingDown.get()) {
                ConsumerRecords<String, String> records = consumer.poll(POLL_TIMEOUT);

                if (records.isEmpty()) {
                    continue;
                }

                // Process each record idempotently
                for (ConsumerRecord<String, String> record : records) {
                    processRecord(record);
                }

                // Commit offsets after processing batch
                consumer.commitSync();
            }
        } catch (WakeupException e) {
            LOG.info("Consumer shutdown initiated via wakeup");
        } catch (Exception e) {
            LOG.error("Error in consumer loop", e);
        } finally {
            consumer.close();
            LOG.info("Consumer closed");
        }
    }

    private void processRecord(ConsumerRecord<String, String> record) {
        try {
            LOG.info("Processing message - Topic: {}, Partition: {}, Offset: {}, Key: {}, Value: {}",
                    record.topic(), record.partition(), record.offset(), record.key(), record.value());
            // Idempotent processing: implementation should handle duplicate messages gracefully
            // This ensures that processing the same message multiple times produces the same result
        } catch (Exception e) {
            LOG.error("Error processing record at offset {}", record.offset(), e);
        }
    }

    public static void main(String[] args) {
        String bootstrapServers = System.getProperty("bootstrap.servers", "localhost:9092");
        String groupId = System.getProperty("group.id", "inventory-consumer-group");

        InventoryConsumer consumer = new InventoryConsumer(bootstrapServers, groupId);
        consumer.run();
    }
}

